import{_ as o,a as r}from"./chunks/inspector_output_separation_labeled.Dcg5c_uG.js";import{_ as a}from"./chunks/showcase_output_separation.Bu6w1WB3.js";import{_ as n,C as i,o as d,c as s,E as c,a2 as p}from"./chunks/framework.CkaEw-3u.js";const l="/mug-typography-docs/image/manual-order.webp",S=JSON.parse('{"title":"Output Settings","description":"Output separation, Write On, display order, and Targets syntax","frontmatter":{"title":"Output Settings","description":"Output separation, Write On, display order, and Targets syntax","pageClass":"reference-page","head":[["link",{"rel":"canonical","href":"https://mug-lab-3.github.io/mug-typography-docs/en/reference/reference-output-settings.html"}],["meta",{"property":"og:type","content":"website"}],["meta",{"property":"og:site_name","content":"Mug Typography Manual"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:title","content":"Output Settings | Mug Typography Manual"}],["meta",{"property":"og:description","content":"Output separation, Write On, display order, and Targets syntax"}],["meta",{"property":"og:url","content":"https://mug-lab-3.github.io/mug-typography-docs/en/reference/reference-output-settings.html"}],["meta",{"property":"og:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.jpg"}],["meta",{"property":"og:image:type","content":"image/jpeg"}],["meta",{"property":"og:image:width","content":"1200"}],["meta",{"property":"og:image:height","content":"630"}],["meta",{"property":"og:image:alt","content":"Mug Typography Online Manual"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:site","content":"@MugLab3"}],["meta",{"name":"twitter:title","content":"Output Settings | Mug Typography Manual"}],["meta",{"name":"twitter:description","content":"Output separation, Write On, display order, and Targets syntax"}],["meta",{"name":"twitter:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.jpg"}],["meta",{"name":"twitter:image:alt","content":"Mug Typography Online Manual"}]]},"headers":[],"relativePath":"en/reference/reference-output-settings.md","filePath":"en/reference/reference-output-settings.md"}'),h={name:"en/reference/reference-output-settings.md"};function g(u,t,m,f,b,y){const e=i("ReferenceOverview");return d(),s("div",null,[c(e,{eyebrow:"PARAMETER REFERENCE",title:"Output Settings",description:"Separate characters or parts into outputs, then control their visible range and reveal order for compositing and Write On.",items:[{icon:"⑂",title:"Separation",description:"Split output into up to three streams",href:"#parameters"},{icon:"✎",title:"Write On",description:"Reveal characters or parts in sequence",href:"#write-on-reveal-filter"},{icon:"↕",title:"Manual Order",description:"Specify the reveal order explicitly",href:"#write-on-reveal-filter"},{icon:"{}",title:"Targets",description:"Syntax for selecting characters and parts",href:"#targets-format"}]}),t[0]||(t[0]=p('<p><a id="page-output-settings"></a></p><p>Configures settings to isolate/extract only specific parts or characters as a separate output, or to render only select elements.<br> By using this feature, you can output only specific parts with a transparent background for multiple instances of the same text, enabling advanced compositing by applying different colors and effects to each part in subsequent nodes.</p><p><img src="'+o+'" alt="Output Settings Page"></p><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><strong>Enable Output Separation</strong></td><td>Enables the output separation feature. When ON, the following parameters appear.</td><td>OFF</td></tr><tr><td><strong>Output Mode</strong></td><td>Specifies how the separation targets are rendered. Select from the following three:<br>・<strong>Default</strong>: Renders only the parts <em>not included in either</em> Separation 1 or Separation 2 targets (bounding box background is also rendered).<br>・<strong>Separation 1 Only</strong>: Renders <em>only</em> the parts specified in Separation 1 Targets (bounding box background is not rendered).<br>・<strong>Separation 2 Only</strong>: Renders <em>only</em> the parts specified in Separation 2 Targets (bounding box background is not rendered).</td><td>Default</td></tr><tr><td><strong>Separation 1 Targets</strong></td><td>A text input field for specifying the characters/parts to include in the first separation group. For the notation, see &quot;<a href="#targets-format">Targets Format</a>&quot; below.<br><strong>If left empty, this separation group contains nothing</strong> (i.e. the group has no targets).</td><td>(empty)</td></tr><tr><td><strong>Separation 2 Targets</strong></td><td>A text input field for specifying the characters/parts to include in the second separation group. Uses the same format as Separation 1 Targets (an empty field contains nothing).</td><td>(empty)</td></tr></tbody></table><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>When duplicating an instanced node on the Fusion page for output separation, <strong>deinstance Output Mode</strong> after duplication. Then set one node to <code>Default</code> and the other to <code>Separation 1 Only</code> or <code>Separation 2 Only</code>. If it remains instanced, Output Mode changes on both nodes together.</p></div><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>For separation targets (Separation 1 / 2 Targets), <strong>an empty field means the group contains nothing (no targets)</strong>. Note that this is the opposite of the Targets field for the Path Deformation / Hand Drawn effects described later, where an empty field means <em>everything</em> is targeted.</p></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>Workflow Example</strong></p><ol><li>Copy the effect node to create three instances.</li><li>On the first node, turn <code>Enable Output Separation</code> ON, set <code>Output Mode</code> to <code>Default</code>, specify <code>c1</code> in <code>Separation 1 Targets</code> and <code>c2</code> in <code>Separation 2 Targets</code> (renders everything except the 1st and 2nd characters).</li><li>On the second node, turn <code>Enable Output Separation</code> ON, set <code>Output Mode</code> to <code>Separation 1 Only</code>, and specify <code>c1</code> in <code>Separation 1 Targets</code> (renders only the 1st character).</li><li>On the third node, turn <code>Enable Output Separation</code> ON, set <code>Output Mode</code> to <code>Separation 2 Only</code>, and specify <code>c2</code> in <code>Separation 2 Targets</code> (renders only the 2nd character).</li><li>Apply different effects to each node and merge them together to create animations where each character has its own distinct effect.</li></ol></div><p><img src="'+r+'" alt="Output Separation Workflow Example"><em>(Output separation setup example. Left: Output Mode = Separation 1 Only, Right: Output Mode = Default)</em></p><p><img src="'+a+'" alt="Composite Result"><em>(Final composite result. Left: Separation 1 Only with effect applied, Right: Final Composite)</em></p><hr><p><a id="write-on"></a></p><h2 id="write-on-reveal-filter" tabindex="-1">Write On (Reveal Filter) <a class="header-anchor" href="#write-on-reveal-filter" aria-label="Permalink to &quot;Write On (Reveal Filter)&quot;">​</a></h2><p><strong>Write On</strong> is a filter that progressively reveals or hides the characters or parts of your text, from beginning to end.<br> By keyframing the <code>Start</code> and <code>End</code> parameters on the timeline, you can easily create a &quot;handwriting&quot; animation where characters appear one by one.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><strong>Unit</strong></td><td>Selects the unit for the filter.<br>· <strong>Character</strong>: Filters by character. Only characters within the <code>Start</code>–<code>End</code> range are rendered.<br>· <strong>Part</strong>: Filters by part. Combine with <code>Stroke Order</code> to reveal parts in an order close to the writing order.</td><td>Character</td></tr><tr><td><strong>Start</strong></td><td>Sets the start of the visible range as a fraction from <code>0.0</code> (beginning) to <code>1.0</code> (end). Animatable.</td><td><code>0.0</code></td></tr><tr><td><strong>End</strong></td><td>Sets the end of the visible range as a fraction from <code>0.0</code> (beginning) to <code>1.0</code> (end). Animatable.</td><td><code>1.0</code></td></tr><tr><td><strong>Stroke Order</strong></td><td>When ON, reorders each character’s parts so they reveal in a natural-looking order. <strong>Especially effective when Unit is Part</strong> — parts appear in roughly stroke-writing order, producing a write-on effect.</td><td>OFF</td></tr><tr><td><strong>Manual Order</strong></td><td>When ON, the characters/parts listed in the <strong>Manual Order List</strong> are revealed and drawn first, in the order listed. Anything not listed follows afterwards in the normal order.</td><td>OFF</td></tr><tr><td><strong>Manual Order List</strong></td><td>A text field (multi-line) listing characters/parts in the order they should reveal and draw. Uses the same syntax as the &quot;<a href="#targets-format">Targets Format</a>&quot;: <code>c&lt;n&gt;</code> (character), <code>p&lt;n&gt;</code> (part), and ranges such as <code>c1-c3</code> (note: since this expresses an order, the exclusion prefix <code>!</code> is not supported). If the same part appears more than once, its first occurrence wins.</td><td>(empty)</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>When to use Manual Order</strong> Write On normally reveals text in a fixed order, from the first character to the last. With Manual Order you can make characters appear in <strong>any order you like</strong>, e.g. <code>c3, c1, c2</code>. When combined with <code>Stroke Order</code>, the parts expanded from a <code>c&lt;n&gt;</code> token follow the stroke-order sequence.</p></div><p><img src="'+l+'" alt="Manual Order example"></p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>How to create a Write On animation</strong></p><ol><li>Set <code>Unit</code> to <code>Part</code> and turn <code>Stroke Order</code> ON.</li><li>At the animation start frame, keyframe <code>End</code> to <code>0.0</code>.</li><li>At the animation end frame, keyframe <code>End</code> to <code>1.0</code>.</li><li>That’s it — you now have an animation that draws the text stroke by stroke.</li></ol></div><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>When both <code>Start</code> and <code>End</code> are at their default values (<code>Start = 0.0</code>, <code>End = 1.0</code>), the Write On filter is inactive (everything is shown).</p></div><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p><strong>About the Stroke Order reveal sequence</strong><br> The reordering done by <code>Stroke Order</code> does not reproduce the actual, correct writing order of a character. It uses an internal algorithm to <em>estimate</em> a plausible order from the positions of the parts, so it may differ from the real stroke order. Also, how a character splits into parts depends on the font&#39;s data structure (see <a href="#overview">Overview</a>), so <strong>the reveal order can change when you switch fonts, even for the same character</strong>. Preview with your actual font to confirm the order is what you intended.</p></div><p><a id="targets-format"></a></p><h2 id="targets-format" tabindex="-1">Targets Format <a class="header-anchor" href="#targets-format" aria-label="Permalink to &quot;Targets Format&quot;">​</a></h2><p>The <code>Separation 1 / 2 Targets</code> of Output Separation and the <code>Targets</code> field of the Path Deformation and Hand Drawn effects all use the same notation to specify the target characters/parts.</p><p>List one or more tokens (units of specification) separated by <strong>commas (<code>,</code>) or spaces</strong>. Each token can use the following notations (<strong>case-insensitive</strong> — <code>c1</code> and <code>C1</code> are the same):</p><table tabindex="0"><thead><tr><th>Notation</th><th>Meaning</th><th>Example</th></tr></thead><tbody><tr><td><code>c&lt;n&gt;</code></td><td><strong>Character unit.</strong> Specifies <strong>all parts</strong> that compose the <code>n</code>-th character (1-based).</td><td><code>c1</code> = all parts of the 1st character</td></tr><tr><td><code>p&lt;n&gt;</code></td><td><strong>Part unit.</strong> Specifies the <code>n</code>-th part globally (1-based).</td><td><code>p5</code> = the 5th part</td></tr><tr><td><code>&lt;n&gt;</code></td><td><strong>No prefix.</strong> Same as <code>p&lt;n&gt;</code>; specifies the <code>n</code>-th part.</td><td><code>15</code> = the 15th part (same as <code>p15</code>)</td></tr><tr><td><code>&lt;a&gt;-&lt;b&gt;</code></td><td><strong>Range.</strong> Specifies everything from <code>a</code> to <code>b</code>, inclusive. See below for details.</td><td><code>c1-c3</code>, <code>p2-p5</code>, <code>2-5</code></td></tr><tr><td><code>!&lt;token&gt;</code></td><td><strong>Negation (exclusion).</strong> Prefixing a token with <code>!</code> <strong>excludes</strong> the targets it would otherwise select. See below.</td><td><code>!c2</code>, <code>!p3</code>, <code>!2-5</code></td></tr></tbody></table><h3 id="details-of-range-specification" tabindex="-1">Details of range specification (<code>-</code>) <a class="header-anchor" href="#details-of-range-specification" aria-label="Permalink to &quot;Details of range specification (`-`)&quot;">​</a></h3><ul><li>Both endpoints of a range must be the <strong>same kind</strong> (character-to-character or part-to-part). Mixed-kind ranges (e.g. <code>c1-p3</code>) are invalid and ignored.</li><li><strong>You only need to add a prefix to one endpoint.</strong> The endpoint without a prefix <strong>inherits the kind of the other endpoint</strong>. <ul><li><code>c1-3</code> is the same as <code>c1-c3</code> (characters 1–3). You don&#39;t have to write out <code>c1-c3</code> in full.</li><li><code>1-3</code> is the same as <code>p1-p3</code> (parts 1–3).</li><li>Inheritance works in reversed order too: <code>c3-1</code> becomes <code>c3-c1</code> → sorted to <code>c1-c3</code>.</li></ul></li><li>Even if the start and end are reversed (e.g. <code>c3-c1</code>), the range is automatically sorted into ascending order.</li></ul><h3 id="details-of-negation" tabindex="-1">Details of negation (<code>!</code>) <a class="header-anchor" href="#details-of-negation" aria-label="Permalink to &quot;Details of negation (`!`)&quot;">​</a></h3><ul><li>A token prefixed with <code>!</code> removes its targets from the result. It works with ranges and character units too (e.g. <code>!c2</code>, <code>!p3-p5</code>).</li><li><strong>Token order does not matter.</strong> All inclusions and exclusions are accumulated, and then <strong>exclusion wins</strong> (if the same part is both included and excluded, it is dropped from the targets).</li><li>Negation is handy in combination with each effect&#39;s &quot;empty behavior&quot; (see below).</li></ul><h3 id="empty-field-behavior-important-—-opposite-per-feature" tabindex="-1">Empty-field behavior (important — opposite per feature) <a class="header-anchor" href="#empty-field-behavior-important-—-opposite-per-feature" aria-label="Permalink to &quot;Empty-field behavior (important — opposite per feature)&quot;">​</a></h3><p>What an empty field means <strong>differs (is the opposite)</strong> depending on the feature.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Meaning when empty</th></tr></thead><tbody><tr><td><strong>Path Deformation / Hand Drawn effects</strong> (Targets)</td><td><strong>All characters/parts are targeted.</strong></td></tr><tr><td><strong>Output Separation</strong> (Separation 1 / 2 Targets)</td><td><strong>Nothing is included</strong> (no targets).</td></tr></tbody></table><p>Because of this, for the Path Deformation / Hand Drawn effects, if you want to target &quot;everything <strong>except</strong> specific parts,&quot; it is convenient to write only a negation. For example, entering <code>!c1</code> targets <strong>everything</strong> except the 1st character (starting from &quot;empty = all,&quot; with just the 1st character excluded).</p><h3 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Input</th><th>Interpretation</th></tr></thead><tbody><tr><td><code>c1, p12, 15</code></td><td>All parts of the 1st character, the 12th part, and the 15th part</td></tr><tr><td><code>c1-c3</code></td><td>All parts of characters 1–3</td></tr><tr><td><code>c1-3</code></td><td>Same as <code>c1-c3</code> (characters 1–3). The prefix on the end can be omitted</td></tr><tr><td><code>p2-p5</code> / <code>2-5</code></td><td>Parts 2–5 (both are the same)</td></tr><tr><td><code>c1-5 !c3</code></td><td>All of characters 1–5 except character 3</td></tr><tr><td><code>!p3</code> (on a deformation effect)</td><td>All parts except the 3rd part</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p><strong>Invalid specifications are silently ignored</strong> (no error is raised): values &lt;= 0, indices out of range, mixed-kind ranges, and so on.</p></div><hr>',37))])}const x=n(h,[["render",g]]);export{S as __pageData,x as default};
